SELECT CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1 OR demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < :param_2) THEN DATEFROMPARTS(YEAR(demo_finance.dbo.settlements.settled_on), MONTH(demo_finance.dbo.settlements.settled_on), 1) ELSE NULL END AS event_month, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < :param_2) THEN :param_3 WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1 AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) > :param_4) THEN :param_5 WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1 AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < :param_6) THEN :param_7 WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1) THEN DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) ELSE NULL END AS lag_day, CAST(demo_finance.dbo.settlements.loaded_at AS DATE) AS load_epoch_day, CASE WHEN (demo_finance.dbo.settlements.loaded_at IS NOT NULL) THEN demo_finance.dbo.settlements.batch_run ELSE NULL END AS batch_id, demo_finance.dbo.settlements.region AS alt_value, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1) THEN :param_8 ELSE :param_9 END AS is_eligible, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NULL) THEN :param_10 ELSE :param_11 END AS is_null_event_time, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NULL) THEN :param_12 ELSE :param_13 END AS is_null_load_time_only, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_14 AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < :param_15) THEN :param_16 ELSE :param_17 END AS is_negative_clipped, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) < :param_2) THEN :param_18 ELSE :param_19 END AS is_negative_lag_excluded, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1 AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) > :param_20) THEN :param_21 ELSE :param_22 END AS is_overflow, CAST(:param_23 AS INTEGER) AS is_join_unmatched, CAST(:param_24 AS INTEGER) AS is_base_row, CAST(:param_25 AS INTEGER) AS is_ambiguous_base, CASE WHEN (demo_finance.dbo.settlements.settled_on IS NOT NULL AND demo_finance.dbo.settlements.loaded_at IS NOT NULL AND DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.loaded_at) >= :param_1 AND (demo_finance.dbo.settlements.settled_on_raw IS NULL OR DATEDIFF(day, demo_finance.dbo.settlements.settled_on, demo_finance.dbo.settlements.settled_on_raw) != :param_26)) THEN :param_27 ELSE :param_28 END AS is_compare_mismatch, CAST(NULL AS INTEGER) AS lookup_dup, HASHBYTES('SHA2_256', CASE WHEN demo_finance.dbo.settlements.settlement_id IS NULL THEN 0x00 ELSE CAST(0x01 AS varbinary(max)) + CAST(CAST(DATALENGTH(CAST('bigint' AS varbinary(64))) AS int) AS binary(4)) + CAST('bigint' AS varbinary(64)) + CAST(CAST(DATALENGTH(CAST(demo_finance.dbo.settlements.settlement_id AS varbinary(max))) AS int) AS binary(4)) + CAST(demo_finance.dbo.settlements.settlement_id AS varbinary(max)) END + CASE WHEN demo_finance.dbo.settlements.leg IS NULL THEN 0x00 ELSE CAST(0x01 AS varbinary(max)) + CAST(CAST(DATALENGTH(CAST('varchar' AS varbinary(64))) AS int) AS binary(4)) + CAST('varchar' AS varbinary(64)) + CAST(CAST(DATALENGTH(CAST(demo_finance.dbo.settlements.leg AS varbinary(max))) AS int) AS binary(4)) + CAST(demo_finance.dbo.settlements.leg AS varbinary(max)) END) AS key_hash, demo_finance.dbo.settlements.loaded_at AS load_time  INTO #mp_probe 
FROM demo_finance.dbo.settlements 
WHERE demo_finance.dbo.settlements.loaded_at <= :as_of OR demo_finance.dbo.settlements.loaded_at IS NULL
